SELECT year, score
FROM happiness_index
ORDER BY year DESC;

SELECT countries.country_name, pisa_scores.score
FROM countries
JOIN pisa_scores ON countries.country_id = pisa_scores.country_id;

SELECT year
FROM pisa_scores
WHERE country_id = 1;

SELECT c.country_name, cp.score
FROM countries c
JOIN corruption_perceptions cp ON c.country_id = cp.country_id
WHERE cp.year = (
    SELECT MAX(year) FROM corruption_perceptions
) AND cp.score > (
    SELECT AVG(score) FROM corruption_perceptions WHERE year = (
        SELECT MAX(year) FROM corruption_perceptions
    )
)
ORDER BY cp.score DESC;

SELECT AVG(score)
FROM pisa_scores
WHERE year = 2015;

SELECT DISTINCT c.country_name
FROM countries c
INNER JOIN access_logs al ON c.country_id = al.country_id;
